import { IMessageComposer } from '@nitrots/nitro-renderer';

export class EditRoomTileMessageComposer implements IMessageComposer<any[]> {
    private _data: any[];

    /**
     * Send a live edit for a single room tile.
     * @param x Tile X (grid coord)
     * @param y Tile Y (grid coord)
     * @param height Height char: 'x' | '0'..'9' | 'A'..'Z'
     * @param isDoor If true, also set the door to (x,y)
     * @param doorDir Door direction (0–7)
     */
    constructor(
        x: number,
        y: number,
        height: string,
        isDoor: boolean = false,
        doorDir: number = 0
    ) {
        this._data = [x, y, height, isDoor ? 1 : 0, doorDir];
        console.log('[📤] EditRoomTileMessageComposer packet:', this._data);
    }

    public getMessageArray(): any[] {
        return this._data;
    }

    public dispose(): void {
        return;
    }
}
